using SkiaSharp;
using System;
using System.Diagnostics;

const int WIDTH = 8000;
const int HEIGHT = 2000;
const int ITERATIONS = 50;

var info = new SKImageInfo(WIDTH, HEIGHT);
long bytesPerSnapshot = (long)WIDTH * HEIGHT * 4;

Console.WriteLine($"Surface: {WIDTH}x{HEIGHT}, ~{bytesPerSnapshot / (1024 * 1024)}MB per snapshot");
Console.WriteLine($"Running {ITERATIONS} iterations without disposing old snapshots...");

using var surface = SKSurface.Create(info);
var canvas = surface.Canvas;

SKImage? layerBackGround = null;
var process = Process.GetCurrentProcess();

for (int i = 1; i <= ITERATIONS; i++)
{
    if (i == 1)
    {
        canvas.Clear(SKColors.White);
        using var paint = new SKPaint { Color = SKColors.Blue, Style = SKPaintStyle.Fill };
        canvas.DrawRect(0, 0, WIDTH, HEIGHT, paint);
        layerBackGround = surface.Snapshot();
    }
    else
    {
        var rect = new SKRect(0, 0, WIDTH, HEIGHT);
        canvas.DrawImage(layerBackGround!, rect);
        using var paint = new SKPaint { Color = SKColors.Green, Style = SKPaintStyle.Fill };
        canvas.DrawRect(i * 10, i * 5, i * 10 + 50, i * 5 + 50, paint);
        // Missing: layerBackGround?.Dispose();
        layerBackGround = surface.Snapshot();
        using var circlePaint = new SKPaint { Style = SKPaintStyle.Stroke, Color = SKColors.Red };
        canvas.DrawCircle(i * 20, i * 10, 100, circlePaint);
    }

    process.Refresh();
    long memMB = process.WorkingSet64 / (1024 * 1024);
    Console.WriteLine($"Snapshot #{i}: WorkingSet={memMB}MB");
}

process.Refresh();
long finalMemMB = process.WorkingSet64 / (1024 * 1024);
if (finalMemMB > 500)
    Console.WriteLine($"FAILURE: Memory leak confirmed - {finalMemMB}MB consumed");
else
    Console.WriteLine($"SUCCESS: Memory stayed low at {finalMemMB}MB");

layerBackGround?.Dispose();
